@namespace sv_562a133dabc247669ff4d0ade3a03e9f.Components.Apply

<nav class="mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between position-relative step-indicator">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCompleted = step < CurrentStep;
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep;

            <li class="text-center flex-fill position-relative">
                @if (isCompleted)
                {
                    <button class="btn btn-link text-decoration-none p-0" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="badge rounded-circle bg-success d-inline-flex align-items-center justify-content-center" style="width:36px;height:36px;">
                            <span>&#10003;</span>
                        </span>
                        <div class="small mt-1 text-success fw-semibold">@StepNames[step]</div>
                    </button>
                }
                else if (isCurrent)
                {
                    <span class="badge rounded-circle bg-primary d-inline-flex align-items-center justify-content-center" style="width:36px;height:36px;">
                        @(step + 1)
                    </span>
                    <div class="small mt-1 text-primary fw-semibold">@StepNames[step]</div>
                }
                else
                {
                    <span class="badge rounded-circle bg-secondary opacity-50 d-inline-flex align-items-center justify-content-center" style="width:36px;height:36px;">
                        @(step + 1)
                    </span>
                    <div class="small mt-1 text-muted">@StepNames[step]</div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

@namespace sv_562a133dabc247669ff4d0ade3a03e9f.Components.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @Index</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name</label>
                <input class="form-control" value="@Entry.Company"
                       @onchange="e => Update(Entry with { Company = (string?)e.Value ?? string.Empty })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title</label>
                <input class="form-control" value="@Entry.Title"
                       @onchange="e => Update(Entry with { Title = (string?)e.Value ?? string.Empty })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date</label>
                <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? string.Empty) })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@(Entry.EndDate?.ToString("yyyy-MM-dd") ?? string.Empty)"
                       disabled="@IsCurrent"
                       @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" checked="@IsCurrent" id="current-@Index"
                           @onchange="e => ToggleCurrent((bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Entry.Description"
                          @onchange="e => Update(Entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null;

    private void Update(WorkEntry updated) => OnChanged.InvokeAsync(updated);

    private void ToggleCurrent(bool isCurrent)
    {
        var updated = isCurrent
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        OnChanged.InvokeAsync(updated);
    }
}

@namespace sv_562a133dabc247669ff4d0ade3a03e9f.Components.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
