            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship</label>
                <input class="form-control" value="@Ref.Relationship"
                       @onchange="e => Update(Ref with { Relationship = (string?)e.Value ?? string.Empty })" />
            </div>
            <div class="col-md-6">
