<nav class="mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between position-relative step-indicator">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCompleted = step < CurrentStep;
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep;

            <li class="text-center flex-fill position-relative">
                @if (isCompleted)
                {
                    <button class="btn btn-link text-decoration-none p-0" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="badge rounded-circle bg-success d-inline-flex align-items-center justify-content-center" style="width:36px;height:36px;">
                            <span>&#10003;</span>
                        </span>
                        <div class="small mt-1 text-success fw-semibold">@StepNames[step]</div>
                    </button>
                }
                else if (isCurrent)
                {
                    <span class="badge rounded-circle bg-primary d-inline-flex align-items-center justify-content-center" style="width:36px;height:36px;">
                        @(step + 1)
                    </span>
                    <div class="small mt-1 text-primary fw-semibold">@StepNames[step]</div>
                }
                else
                {
                    <span class="badge rounded-circle bg-secondary opacity-50 d-inline-flex align-items-center justify-content-center" style="width:36px;height:36px;">
                        @(step + 1)
                    </span>
                    <div class="small mt-1 text-muted">@StepNames[step]</div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}
