@namespace sv_562a133dabc247669ff4d0ade3a03e9f.Components.Apply

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" value="@Model.FullName"
               @onchange="e => Model = Model with { FullName = (string?)e.Value ?? string.Empty }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" value="@Model.Email"
               @onchange="e => Model = Model with { Email = (string?)e.Value ?? string.Empty }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Model.Phone"
               @onchange="e => Model = Model with { Phone = (string?)e.Value ?? string.Empty }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" value="@Model.Address"
               @onchange="e => Model = Model with { Address = (string?)e.Value ?? string.Empty }" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter] public EventCallback<PersonalInfo> OnNext { get; set; }

    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) || string.IsNullOrWhiteSpace(Model.Email)
            || string.IsNullOrWhiteSpace(Model.Phone) || string.IsNullOrWhiteSpace(Model.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }

            await OnNext.InvokeAsync(Model);
        }
        finally
        {
            IsValidating = false;
        }
    }
}

