@page "/apply"
@rendermode InteractiveServer
@using sv_562a133dabc247669ff4d0ade3a03e9f.Components.Apply
@using sv_562a133dabc247669ff4d0ade3a03e9f.Models
@using sv_562a133dabc247669ff4d0ade3a03e9f.Services

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="@_currentStep" OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep Model="@_personal" OnNext="HandlePersonalNext" />
            break;
        case 1:
            <WorkHistoryStep Entries="@_workEntries" OnNext="HandleWorkNext" OnBack="GoBack" />
            break;
        case 2:
            <ReferencesStep References="@_references" OnNext="HandleReferencesNext" OnBack="GoBack" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="@_coverLetter" OnNext="HandleCoverLetterNext" OnBack="GoBack" />
            break;
        case 4:
            <ReviewStep Application="@BuildApplication()"
                        SubmittedId="@_submittedId"
                        OnEditSection="GoToStep"
                        OnBack="GoBack"
                        OnSubmit="HandleSubmit" />
            break;
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int _currentStep;
    private int? _submittedId;

    private PersonalInfo _personal = new(string.Empty, string.Empty, string.Empty, string.Empty);
    private List<WorkEntry> _workEntries = new() { new(string.Empty, string.Empty, DateTime.Today, null, string.Empty) };
    private List<Reference> _references = new()
    {
        new(string.Empty, string.Empty, string.Empty, string.Empty),
        new(string.Empty, string.Empty, string.Empty, string.Empty)
    };
    private string _coverLetter = string.Empty;

    private void HandlePersonalNext(PersonalInfo info)
    {
        _personal = info;
        _currentStep = 1;
    }

    private void HandleWorkNext(List<WorkEntry> entries)
    {
        _workEntries = entries;
        _currentStep = 2;
    }

    private void HandleReferencesNext(List<Reference> refs)
    {
        _references = refs;
        _currentStep = 3;
    }

    private void HandleCoverLetterNext(string letter)
    {
        _coverLetter = letter;
        _currentStep = 4;
    }

    private async Task HandleSubmit()
    {
        var application = BuildApplication();
        _submittedId = await ApplicationService.SubmitApplicationAsync(application);
    }

    private void GoToStep(int step)
    {
        if (step < _currentStep)
            _currentStep = step;
    }

    private void GoBack() => _currentStep = Math.Max(0, _currentStep - 1);

    private JobApplication BuildApplication() =>
        new(_personal, new WorkHistory(_workEntries), _references, _coverLetter);
}

